module top_module(
    input DATA, LATCH,
    output Q, QNOT
    );wire d, l;
    reg q, qnot;

    wire __d_tmp = DATA;
    assign d = __d_tmp;
    assign l = LATCH;

    always@(d or l)
        if(l)begin
            q <= d;
            qnot <= ~d;
        end

    assign Q = q;
    assign QNOT = qnot;endmodule
